-- Raw-layer schema bootstrap.
-- Generated by intelia from the Oracle inventory. Run once against
-- the BigQuery target before `dataform run`. Idempotent — every
-- statement is CREATE TABLE IF NOT EXISTS.

CREATE SCHEMA IF NOT EXISTS `transformation-agent-demo.migration_raw`
  OPTIONS(description="Source layer replicated from the Oracle warehouse");

CREATE TABLE IF NOT EXISTS `transformation-agent-demo.migration_raw.account_investments` (
  ACCOUNT_ID NUMERIC NOT NULL,
  INVESTMENT_ID NUMERIC NOT NULL,
  ALLOCATION_PERCENTAGE NUMERIC,
  PRIMARY KEY (ACCOUNT_ID, INVESTMENT_ID) NOT ENFORCED
) OPTIONS(description="Source table replicated from Oracle (account_investments)");

